This in footer: 
```html
<script type='text/javascript' src='https://cdn.jsdelivr.net/npm/instantsearch.js@2.10.2'></script>
<script type="text/javascript">
jQuery(function() {
  if (jQuery("#algolia-search-box").length > 0) {
    if (
      algolia.indices.searchable_posts === undefined &&
      jQuery(".admin-bar").length > 0
    ) {
      alert(
        "It looks like you haven't indexed the searchable posts index. Please head to the Indexing page of the Algolia Search plugin and index it."
      );
    }

    /* Instantiate instantsearch.js */
    var search = instantsearch({
      appId: algolia.application_id,
      apiKey: algolia.search_api_key,
      indexName: algolia.indices.searchable_posts.name,
      urlSync: {
        mapping: { q: "s" },
        trackedParameters: ["query"]
      },
      searchParameters: {
        facetingAfterDistinct: true,
        highlightPreTag: "__ais-highlight__",
        highlightPostTag: "__/ais-highlight__",
        filters: 'wpml.locale:"' + current_locale + '"'
      }
    });

    /* Search box widget */
    search.addWidget(
      instantsearch.widgets.searchBox({
        container: "#algolia-search-box",
        placeholder: "Search for...",
        wrapInput: false,
        poweredBy: algolia.powered_by_enabled
      })
    );

    /* Stats widget */
    search.addWidget(
      instantsearch.widgets.stats({
        container: "#algolia-stats"
      })
    );

    /* Hits widget */
    search.addWidget(
      instantsearch.widgets.hits({
        container: "#algolia-hits",
        hitsPerPage: 9,
        templates: {
          empty: 'No results were found for "<strong>{{query}}</strong>".',
          item: wp.template("instantsearch-hit")
        },
        transformData: {
          item: function(hit) {
            function replace_highlights_recursive(item) {
              if (item instanceof Object && item.hasOwnProperty("value")) {
                item.value = _.escape(item.value);
                item.value = item.value
                  .replace(/__ais-highlight__/g, "<em>")
                  .replace(/__\/ais-highlight__/g, "</em>");
              } else {
                for (var key in item) {
                  item[key] = replace_highlights_recursive(item[key]);
                }
              }
              return item;
            }

            hit._highlightResult = replace_highlights_recursive(
              hit._highlightResult
            );
            hit._snippetResult = replace_highlights_recursive(
              hit._snippetResult
            );

            return hit;
          }
        }
      })
    );

    /* Pagination widget */
    search.addWidget(
      instantsearch.widgets.pagination({
        container: "#algolia-pagination"
      })
    );

    search.addWidget(
      instantsearch.widgets.menuSelect({
        container: "#aligolia-condition",
        attributeName: "taxonomies.condition",
        limit: 10,
        templates: {
          header: '<h3 class="widgettitle">Condition</h3>'
        }
      })
    );
  }
});
</script>
```
